class Solution {
public:
    vector<int> popcountDepth(vector<long long>& nums, vector<vector<long long>>& queries) {
        vector<int> res;
        for (auto& query : queries) {
            if (query[0] == 1) {
                int count = 0;
                for (int i = query[1]; i <= query[2]; i++) {
                    int depth = 0;
                    long long num = nums[i];
                    while (num) {
                        num &= (num - 1);
                        depth++;
                    }
                    if (depth == query[3]) count++;
                }
                res.push_back(count);
            } else {
                nums[query[1]] = query[2];
            }
        }
        return res;
    }
};
```
